param([string]$Project='.')
$S=Split-Path -Parent $MyInvocation.MyCommand.Path; . (Join-Path $S 'lib/GodMode.Common.ps1'); $r=Initialize-GodModeStructure $Project
$graphs=@{'lineage.mmd'='graph TD`n  ARCHITECT-->SUMMARIZER';'mission-flow.mmd'='stateDiagram-v2`n  queued --> claimed`n  claimed --> spawning`n  spawning --> running`n  running --> validating`n  validating --> completed';'evolution-tree.mmd'='graph TD`n seed-->active';'skill-map.mmd'='graph TD`n verified_mission-->proposed_skill';'browser-reality.mmd'='graph TD`n BrowserUseUnknown-->ChromeHeadlessStatic';'live-result-flow.mmd'='graph TD`n Master-->ResultState-->LiveViewer';'windows-routing.mmd'='graph TD`n WindowsDoctor-->ToolResolver-->Router';'trace-crystal.mmd'='graph TD`n Mission-->Span-->Ledger'}
foreach($k in $graphs.Keys){Set-Content (Join-GodModePath $r "graphs/$k") $graphs[$k] -Encoding UTF8}; Set-Content (Join-GodModePath $r 'graphs/latest-dashboard.md') "# Aeonthra Graph Dashboard`n`nGenerated $(Get-Date -Format o)." -Encoding UTF8; Write-Host '[DONE] Graph exports updated.'
